<template>
  <div>
    <p v-for="item in groupData" :key="item.id">{{ item.groupName }}（权重为{{ item.weight }}）</p>
    <a-list :grid="{ gutter: 16, column: 1 }" :data-source="data">
      <a-list-item slot="renderItem" slot-scope="item">
        <a-card :title="`${item.contestantName}（${item.description}）`">
          <p v-for="itemScore in item.judgeScoreRecords" :key="itemScore.judgeId">
            {{ itemScore.judgeName }}（{{ itemScore.groupName }}）最终打分：{{ itemScore.score }}分
          </p>
        </a-card>
      </a-list-item>
    </a-list>
  </div>
</template>
<script>
import { getContestantScores } from '@/api/dataAnalysis'
import { getContestantScoreDetail } from '@/api/scoreRecord'
import { voteGroupList } from '@/api/judgeGroup'
export default {
  data() {
    return {
      data: [],
      groupData: [],
      loading: false,
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    async loadData() {
      this.loading = true
      try {
        const res = await getContestantScores(this.$route.params.id)
        voteGroupList(this.$route.params.id).then(res => {
          this.groupData = res.records
        })
        const sortTemp = res.map(item => item.contestantId)
        const tempData = await Promise.all(
          res.map(item => getContestantScoreDetail(this.$route.params.id, item.contestantId))
        )
        tempData.sort((a, b) => sortTemp.indexOf(a.contestantId) - sortTemp.indexOf(b.contestantId))
        this.data = tempData
      } catch (error) {
        console.error('加载数据失败:', error)
      } finally {
        this.loading = false
      }
    },
  },
}
</script>
