import request from '@/utils/request'

export function voteGroupList(voteId) {
  return request({
    url: `/judgeWhitelistGroup/getAllGroups?voteId=${voteId}&page=1&size=100`,
    method: 'get',
  })
}

export function delVoteGroupItem(groupId) {
  return request({
    url: `/judgeWhitelistGroup/deleteGroup?id=${groupId}`,
    method: 'post',
  })
}

export function addVoteGroupItem(data) {
  return request({
    url: `/judgeWhitelistGroup/createGroup`,
    method: 'post',
    data: data,
  })
}

export function updateVoteGroupItem(data) {
  return request({
    url: `/judgeWhitelistGroup/updateGroup`,
    method: 'post',
    data: data,
  })
}
